1	const PROCESSING_FEE = 5;
2	const FIRST_QUOTE_SURCHARGE_RATE = 0.1;
3	const BASE_PRICE_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
14	
15	const itemBasePrice = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
16	
17	const quotePremium = (items: Item[]): number => {
18	  const basePrice = items.reduce((sum, item) => sum + itemBasePrice(item), 0);
19	  const firstQuoteSurcharge = basePrice * FIRST_QUOTE_SURCHARGE_RATE;
20	  return Math.ceil(basePrice + firstQuoteSurcharge + PROCESSING_FEE);
21	};
22	
23	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
24	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
25	  return { results };
26	};
